patch:
diff --git a/llvm/lib/Transforms/Utils/Local.cpp b/llvm/lib/Transforms/Utils/Local.cpp
index 2cfd70a1746c..d5fc8c2fae20 100644
--- a/llvm/lib/Transforms/Utils/Local.cpp
+++ b/llvm/lib/Transforms/Utils/Local.cpp
@@ -2852,8 +2852,14 @@ Instruction *llvm::removeUnwindEdge(BasicBlock *BB, DomTreeUpdater *DTU) {
   BasicBlock *UnwindDest;

   if (auto *CRI = dyn_cast<CleanupReturnInst>(TI)) {
-    NewTI = CleanupReturnInst::Create(CRI->getCleanupPad(), nullptr, CRI->getIterator());
-    UnwindDest = CRI->getUnwindDest();
+    if (auto *CPad = dyn_cast<CleanupPadInst>(CRI->getOperand(0))) {
+      NewTI = CleanupReturnInst::Create(CPad, nullptr, CRI->getIterator());
+      UnwindDest = CRI->getUnwindDest();
+    } else {
+      // The operand is not a CleanupPadInst, which should never happen.
+      // Return the original terminator to avoid crashing.
+      return TI;
+    }
   } else if (auto *CatchSwitch = dyn_cast<CatchSwitchInst>(TI)) {
     auto *NewCatchSwitch = CatchSwitchInst::Create(
         CatchSwitch->getParentPad(), nullptr, CatchSwitch->getNumHandlers(),
diff --git a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
index 850e57e6b0b1..4ed57aebccc2 100644
--- a/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
+++ b/llvm/lib/Transforms/Utils/SimplifyCFG.cpp
@@ -5385,6 +5385,21 @@ static bool removeEmptyCleanup(CleanupReturnInst *RI, DomTreeUpdater *DTU) {
     // This isn't an empty cleanup.
     return false;

+  // Check that all predecessors have terminators that can be handled by removeUnwindEdge.
+  for (BasicBlock *PredBB : predecessors(BB)) {
+    Instruction *TI = PredBB->getTerminator();
+    if (isa<InvokeInst>(TI))
+      continue;
+    if (auto *CRI = dyn_cast<CleanupReturnInst>(TI)) {
+      if (!isa<CleanupPadInst>(CRI->getOperand(0)))
+        return false;
+      continue;
+    }
+    if (isa<CatchSwitchInst>(TI))
+      continue;
+    // Unknown terminator, cannot remove unwind edge.
+    return false;
+  }
   // We cannot kill the pad if it has multiple uses.  This typically arises
   // from unreachable basic blocks.
   if (!CPInst->hasOneUse())
@@ -5465,6 +5480,10 @@ static bool removeEmptyCleanup(CleanupReturnInst *RI, DomTreeUpdater *DTU) {
         DTU->applyUpdates(Updates);
         Updates.clear();
       }
+      if (auto *CRI = dyn_cast<CleanupReturnInst>(PredBB->getTerminator())) {
+        if (!isa<CleanupPadInst>(CRI->getOperand(0)))
+          continue;
+      }
       removeUnwindEdge(PredBB, DTU);
       ++NumInvokes;
     } else {

